from __future__ import annotations

import base64
import ssl
import typing
import urllib.parse

# Functions for typechecking...


ByteOrStr = typing.Union[bytes, str]
HeadersAsSequence = typing.Sequence[typing.Tuple[ByteOrStr, ByteOrStr]]
HeadersAsMapping = typing.Mapping[ByteOrStr, ByteOrStr]
HeaderTypes = typing.Union[HeadersAsSequence, HeadersAsMapping, None]

Extensions = typing.MutableMapping[str, typing.Any]


def enforce_bytes(value: bytes | str, *, name: str) -> bytes:
    """
    Ensure a value is returned as bytes. Strings are encoded as ASCII and must
    contain only ASCII characters; otherwise a TypeError is raised.
    """
    if isinstance(value, str):
        try:
            return value.encode("ascii")
        except UnicodeEncodeError:
            raise TypeError(f"{name} strings may not include unicode characters.")
    elif isinstance(value, bytes):
        return value

    seen_type = type(value).__name__
    raise TypeError(f"{name} must be bytes or str, but got {seen_type}.")


def enforce_url(value: "URL | bytes | str", *, name: str) -> "URL":
    """
    Ensure the value is a URL instance. bytes or str values are converted into
    a URL by parsing.
    """
    if isinstance(value, (bytes, str)):
        return URL(value)
    elif isinstance(value, URL):
        return value

    seen_type = type(value).__name__
    raise TypeError(f"{name} must be a URL, bytes, or str, but got {seen_type}.")


def enforce_headers(
    value: HeadersAsMapping | HeadersAsSequence | None = None, *, name: str
) -> list[tuple[bytes, bytes]]:
    """
    Convienence function that ensure all items in request or response headers
    are either bytes or strings in the plain ASCII range. Returns a list of
    (name, value) pairs as bytes.
    """
    if value is None:
        return []
    elif isinstance(value, typing.Mapping):
        return [
            (
                enforce_bytes(k, name="header name"),
                enforce_bytes(v, name="header value"),
            )
            for k, v in value.items()
        ]
    elif isinstance(value, typing.Sequence):
        return [
            (
                enforce_bytes(k, name="header name"),
                enforce_bytes(v, name="header value"),
            )
            for k, v in value
        ]

    seen_type = type(value).__name__
    raise TypeError(
        f"{name} must be a mapping or sequence of two-tuples, but got {seen_type}."
    )


def enforce_stream(
    value: bytes | typing.Iterable[bytes] | typing.AsyncIterable[bytes] | None,
    *,
    name: str,
) -> typing.Iterable[bytes] | typing.AsyncIterable[bytes]:
    """
    Normalize a body/stream value into either an iterable of bytes or an async
    iterable of bytes. If None or a raw bytes object is provided, return a
    ByteStream wrapper that yields that content.
    """
    if value is None:
        return ByteStream(b"")
    elif isinstance(value, bytes):
        return ByteStream(value)
    return value


# * https://tools.ietf.org/html/rfc3986#section-3.2.3
# * https://url.spec.whatwg.org/#url-miscellaneous
# * https://url.spec.whatwg.org/#scheme-state
DEFAULT_PORTS = {
    b"ftp": 21,
    b"http": 80,
    b"https": 443,
    b"ws": 80,
    b"wss": 443,
}


def include_request_headers(
    headers: list[tuple[bytes, bytes]],
    *,
    url: "URL",
    content: None | bytes | typing.Iterable[bytes] | typing.AsyncIterable[bytes],
) -> list[tuple[bytes, bytes]]:
    """
    Ensure that essential request headers are included.

    - Adds a Host header if one is not present.
    - Adds a Content-Length header for fixed-length bodies when appropriate.
    - Adds a Transfer-Encoding: chunked header for streaming bodies when no
      content-length is present.
    """
    headers_set = set(k.lower() for k, v in headers)

    if b"host" not in headers_set:
        default_port = DEFAULT_PORTS.get(url.scheme)
        if url.port is None or url.port == default_port:
            header_value = url.host
        else:
            header_value = b"%b:%d" % (url.host, url.port)
        headers = [(b"Host", header_value)] + headers

    if (
        content is not None
        and b"content-length" not in headers_set
        and b"transfer-encoding" not in headers_set
    ):
        if isinstance(content, (bytes, bytearray)):
            content_length = str(len(content)).encode("ascii")
            headers += [(b"Content-Length", content_length)]
        else:
            # For streaming/iterable bodies that are not raw bytes, use chunked.
            headers += [(b"Transfer-Encoding", b"chunked")]

    return headers


class URL:
    """
    Minimal URL representation that accepts strings or bytes and exposes basic
    components as bytes. Designed to be lightweight for use in header handling
    and comparisons.
    """

    def __init__(self, url: bytes | str | "URL") -> None:
        """
        Initialize a URL from a bytes/string or copy from another URL.
        The original textual representation is preserved in bytes form.
        """
        if isinstance(url, URL):
            # Copy constructor
            self._raw = url._raw
        elif isinstance(url, bytes):
            self._raw = url
        elif isinstance(url, str):
            try:
                self._raw = url.encode("ascii")
            except UnicodeEncodeError:
                # Use percent-encoding for non-ascii characters
                self._raw = url.encode("utf-8")
        else:
            raise TypeError("URL must be a URL, bytes, or str")

        text = self._raw.decode("utf-8", errors="surrogateescape")
        split = urllib.parse.urlsplit(text)
        self.scheme = enforce_bytes(split.scheme or "", name="scheme").lower()
        host = split.hostname or ""
        self.host = enforce_bytes(host, name="host")
        self.port = split.port
        # preserve path and query in bytes
        path = split.path or ""
        query = ("?" + split.query) if split.query else ""
        self.path = enforce_bytes(path + query, name="path")
        self.raw = self._raw

    def __iter__(self):
        """
        Iterate over the URL components as (scheme, host, port, path).
        """
        yield self.scheme
        yield self.host
        yield self.port
        yield self.path

    def __repr__(self) -> str:
        """
        Return a developer-friendly representation of the URL.
        """
        try:
            display = self._raw.decode("utf-8")
        except Exception:
            display = str(self._raw)
        return f"URL({display!r})"

    def __str__(self) -> str:
        """
        Return the textual form of the URL.
        """
        try:
            return self._raw.decode("utf-8")
        except Exception:
            return str(self._raw)

    @property
    def origin(self) -> "Origin":
        """
        Return an Origin object representing the scheme, host and port.
        """
        return Origin(self.scheme, self.host, self.port)

    def __eq__(self, other: typing.Any) -> bool:
        """
        Compare URLs based on their raw byte representation.
        """
        if isinstance(other, URL):
            return self._raw == other._raw
        if isinstance(other, (bytes, str)):
            try:
                other_url = URL(other)
            except Exception:
                return False
            return self._raw == other_url._raw
        return False

    def __bytes__(self) -> bytes:
        """
        Return the raw bytes used to construct the URL.
        """
        return self._raw


class Origin:
    """
    Representation of a request origin (scheme, host, port).
    """

    def __init__(self, scheme: bytes | str, host: bytes | str, port: int | None):
        """
        Initialize an Origin. scheme and host are stored as bytes.
        """
        self.scheme = enforce_bytes(scheme, name="origin scheme").lower()
        self.host = enforce_bytes(host, name="origin host")
        self.port = port

    def __eq__(self, other: typing.Any) -> bool:
        """
        Compare two Origin objects for equality.
        """
        if not isinstance(other, Origin):
            return False
        return (
            self.scheme == other.scheme
            and self.host == other.host
            and self.port == other.port
        )

    def __repr__(self) -> str:
        """
        Return a developer-friendly representation of the Origin.
        """
        return f"Origin(scheme={self.scheme!r}, host={self.host!r}, port={self.port!r})"


class ByteStream:
    """
    A simple wrapper for byte content that provides a synchronous iterator and
    convenience methods for reading content as a single bytes object.
    """

    def __init__(self, content: bytes | typing.Iterable[bytes] | typing.AsyncIterable[bytes]):
        """
        Initialize a ByteStream with either raw bytes, a synchronous iterable
        of bytes, or an asynchronous iterable of bytes.
        """
        self._is_bytes = isinstance(content, (bytes, bytearray))
        if self._is_bytes:
            # store as immutable bytes
            self._data = bytes(content)
            self._iterable = None
        else:
            # Accept either sync iterable or async iterable
            self._data = None
            self._iterable = content

        self._closed = False

    def __repr__(self) -> str:
        """
        Return a developer-friendly representation of the ByteStream.
        """
        if self._is_bytes:
            return f"ByteStream({len(self._data)} bytes)"
        else:
            return "ByteStream(stream)"

    @property
    def content(self) -> bytes:
        """
        Return the full content as bytes. If initialized from an iterable,
        the iterable will be consumed.
        """
        if self._is_bytes:
            return self._data
        # consume iterable to bytes
        chunks = []
        if self._iterable is None:
            return b""
        for chunk in self._iterable:  # type: ignore
            chunks.append(bytes(chunk))
        self._data = b"".join(chunks)
        self._is_bytes = True
        self._iterable = None
        return self._data

    def read(self) -> bytes:
        """
        Read and return the entire stream content as bytes.
        """
        return self.content

    def iter_stream(self) -> typing.Iterator[bytes]:
        """
        Return a synchronous iterator over the stream content yielding bytes.
        If the stream was initialized with raw bytes, yields that content once.
        """
        if self._closed:
            return
            yield  # pragma: no cover
        if self._is_bytes:
            yield self._data
        else:
            assert self._iterable is not None
            for chunk in self._iterable:  # type: ignore
                yield bytes(chunk)

    def close(self) -> None:
        """
        Mark the stream as closed. After closing, no further content will be
        yielded.
        """
        self._closed = True


# Example simple Request/Response placeholders that might have needed __init__
class Request:
    """
    Minimal Request representation to demonstrate ByteStream and URL usage.
    """

    def __init__(
        self,
        method: bytes | str,
        url: URL | bytes | str,
        headers: HeaderTypes = None,
        content: None | bytes | typing.Iterable[bytes] | typing.AsyncIterable[bytes] = None,
    ):
        """
        Initialize a Request with method, URL, headers, and an optional body.
        Headers are normalized to a list of byte pairs. The body is wrapped
        with enforce_stream.
        """
        self.method = enforce_bytes(method, name="method").upper()
        self.url = enforce_url(url, name="url")
        self.headers = enforce_headers(headers, name="headers")
        self.stream = enforce_stream(content, name="content")

    def __repr__(self) -> str:
        """
        Developer friendly representation of Request.
        """
        try:
            return f"Request(method={self.method!r}, url={self.url!r})"
        except Exception:
            return "Request(...)"

